public class CustomCriterion extends AbstractCriterion<CustomCriterion.Conditions> {
    private static final Identifier ID = new Identifier("modid", "custom");
    @Override
    public Identifier getId() { return ID; }
    @Override
    protected Conditions conditionsFromJson(JsonObject obj) { return new Conditions(); }
    public void trigger(ServerPlayerEntity player) { this.trigger(player, conditions -> true); }
    public static class Conditions implements AbstractCriterion.Conditions {}
}

public static final CustomCriterion CUSTOM_CRITERION = new CustomCriterion();
// 在模组初始化时
Criteria.register(CUSTOM_CRITERION);

public static class Conditions implements AbstractCriterion.Conditions {
    private final int requiredValue;
    public Conditions(int requiredValue) { this.requiredValue = requiredValue; }
    public boolean matches(int value) { return value >= requiredValue; }
}

public static class NbtConditions implements AbstractCriterion.Conditions {
    private final NbtCompound requiredNbt;
    public NbtConditions(NbtCompound requiredNbt) { this.requiredNbt = requiredNbt; }
    public boolean matches(NbtCompound actualNbt) { return actualNbt.equals(requiredNbt); }
}

public class CustomRewardFunction {
    public static void apply(ServerPlayerEntity player) {
        player.addExperience(100);
        player.getInventory().offerOrDrop(new ItemStack(ModItems.CUSTOM_ITEM));
    }
}
